uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uvo = vUvOriginal;
uv1 = (vUvOriginal-.5);//*uAspect.xy;

float z = 1/abs(uv1.y+.3);
rs.x = uv1.x*10;
rs.y = z*2;
rs0 = rs;
rs *=2;


c = uv1*4+vec2(-.5,0);
//c = rs*.1;
zz = c;

for (n=1; n<=6; n++)
{
tmp = zz;
zz.x = tmp.x*tmp.x - tmp.y*tmp.y;
zz.y = 2*tmp.x * tmp.y;
zz = zz + c;
}

float len=dot(zz,zz);

ret = texture(sampler_noise_lq,abs(zz)/12) * .15/(len+2);
//ret += (-0.001*(1/ (len+2)));
ret += texture(sampler_fc_main, vUv+ zz*q18);

//ret += GetBlur2 (fract(uvo))*.8 * clamp01(len-6);

ret *= 1;
ret = ret *.99-.01;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uvo = vUvOriginal;

uv1 = vUv-vec2 (.5,1);
uv1 *= uAspect.xy;
hinten = 1/(uv1.y-0.1);//sqrt nur Verringerung Rechenzeit
hinten = clamp(hinten,-6,0);
bfly = 0;
float trel = uTime; ;
for (n=1; n <= 2; n++)
{  k = 0;
   z0 = n*1.5;
   rs.x = (uv1.x)*z0*hinten + n/4;//Zentrum x
   rs.y = z0*hinten-trel;

   //noise1 ist Maske fuer Desync der Fluegelschlaege
   //Problem: k erst nachher bekannt, deshalb muss
   //Amplitude oder Groesse begrenzt werden
   noise1 = texture(sampler_pw_noise_lq,rs/256);

   k += .4*sin(uTime*16* (.5+noise1.r)); //Fluegelschlag
   z = k*abs((fract(rs.x))-.5)+ z0;
 //  z -= .5*clamp01(.05-pow(sin(6.3*(rs.x)),2)); //Rumpfform
   z -= .04*k; //Koerperbewegung
   rs.y = z*hinten-trel;
   rs = fract(rs.yx) ;
   neu = GetBlur1(rs) - (1-q18*16)*GetBlur2(rs);
   neu *= normalize(noise1) * 8*clamp01(6+hinten)/hinten;
   bfly += abs(neu) * (lum(noise1) >= .86) * (hinten <= 0);
}

//Wolken
vec2 uv4 = uv1;
float z4 = clamp(1/(abs(uv4.y-.1)),-0,18);
rs = vec2(uv4.x * z4, z4*2+uTime)/12 ;
vec3 clouds = lum(texture(sampler_noise_hq,rs+.0*uTime));
clouds *= clamp01(1-vUv.y) ;
clouds *= vec3 (.4,.7, 1-uv4.y)*.5;

//Buschwerk
bush = 0;
for (n=0; n<=1; n++) {
  vec2 uv5 = uv1+vec2 (0,-n*.04);
  uv5.x += (vUv.y*1.05* (q19*(n%2) + q20*((n+1)%2)));
  neu = abs(uv5.y)
  *(1+texture(sampler_noise_lq,vec2(uv5.x*2,uv5.y*4)).g)
  *(3+2*texture(sampler_noise_hq,uv5.x/2*(1+n%2)).g);
  neu = clamp01(.2*neu-.4) * clamp01(-8*uv5.y);
  float red = .5+.5*texture(sampler_noise_hq,uv5*2);
  float vis = clamp01(4*texture(sampler_noise_hq,uv5*8)
  *texture(sampler_noise_hq,uv5*24));

  neu *= vec3 (2*red,1,.2) *vis ;
  bush = max(bush,neu);

}

vec3 scene = clamp01(clouds*(1-32*bush)) + bush;

ret = scene*clamp01(1-8*bfly)+bfly;
//ret = bfly*2;
//ret = GetPixel (uvo)*2;

  fragColor = ret;
}
